public class UserService {
    @Autowired
    private UserRepository userRepository;
    @Autowired
    private PostRepository postRepository;

    public User createUserWithPosts(String name, String email, List<Post> posts) {
        User user = new User();
        user.setName(name);
        user.setEmail(email);
        user.setPosts(posts);

